import type { ApiError } from "tornapi-typescript";
import { api, factiondata, settings, userdata } from "@/utils/common/data/database";
import { ttStorage } from "@/utils/common/data/storage";
import { ttUsage } from "@/utils/common/data/usage";
import { getBadgeText, setBadge } from "@/utils/common/functions/extension";
import { getRFC } from "@/utils/common/functions/torn";
import { SCRIPT_TYPE, TO_MILLIS } from "@/utils/common/functions/utilities";
import { BACKGROUND_SERVICE } from "@/utils/services/proxy-services";

// On Safari iOS, the content-script -> background proxy-service RPC returns
// "No response" too often (event-page lifecycle drops the channel before the
// background's async fetch resolves). Detect Safari and have relay-enabled
// fetches happen directly from the content script context instead, relying
// on the user's granted optional_host_permissions for CORS.
const IS_SAFARI = typeof navigator !== "undefined"
    && /Safari/.test(navigator.userAgent)
    && !/Chrome/.test(navigator.userAgent)
    && !/Chromium/.test(navigator.userAgent);

export const CUSTOM_API_ERROR = {
	NO_NETWORK: "tt-no_network",
	NO_PERMISSION: "tt-no_permission",
	CANCELLED: "tt-cancelled",
} as const;

export const FETCH_PLATFORMS = {
	tornv2: "https://api.torn.com/v2/",
	torn_direct: "https://www.torn.com/",
	yata: "https://yata.yt/",
	tornstats: "https://www.tornstats.com/",
	torntools: "https://torntools.gregork.com/",
	nukefamily: "https://nuke.family/",
	uhc: "https://tornuhc.eu/",
	stig: "https://api.no1irishstig.co.uk/",
	prometheus: "https://prombot.co.uk/",
	lzpt: "https://api.lzpt.io/",
	wtf: "https://what-the-f.de/",
	tornw3b: "https://weav3r.dev/",
	ffscouter: "https://ffscouter.com/",
	laekna: "https://laekna-revive-bot.onrender.com/",
	tornintel: "https://torn-intel.com/",
} as const;

export const FACTION_ACCESS = {
	none: "none",
	basic: "basic",
	full_access: "full_access",
} as const;

export interface FetchOptions {
	fakeResponse: boolean;
	section: string;
	id: undefined | string | number;
	selections: string[];
	legacySelections: string[];
	key: undefined | string;
	action: undefined | string;
	method: "GET" | "POST";
	body: undefined | any;
	silent: boolean;
	succeedOnError: boolean;
	includeKey: boolean;
	relay: boolean;
	params: { [key: string]: any };
}

export type FetchLocation = keyof typeof FETCH_PLATFORMS | typeof FETCH_PLATFORMS.tornstats;

export async function fetchData<R = any>(l: FetchLocation, partialOptions: Partial<FetchOptions> = {}): Promise<R> {
	const options: FetchOptions = {
		fakeResponse: false,
		section: undefined,
		id: undefined,
		selections: [],
		legacySelections: [],
		key: undefined,
		action: undefined,
		method: "GET",
		body: undefined,
		silent: false,
		succeedOnError: false,
		includeKey: false,
		relay: false,
		params: {},
		...partialOptions,
	};

	if (options.relay && SCRIPT_TYPE !== "BACKGROUND" && !IS_SAFARI) {
		return new Promise((resolve, reject) => {
			(BACKGROUND_SERVICE.fetchRelay(l, { ...options, relay: false }) as Promise<R>)
				.then((response) => resolve(response))
				.catch((error) => {
					if (error.name === "NonError") {
						reject(JSON.parse(error.message));
					} else {
						reject(new Error(error));
					}
				});
		});
	}
	// On Safari, fall through to direct fetch (relay disabled by the
	// IS_SAFARI bypass above). The actual fetch logic below handles it.

	return new Promise(async (resolve, reject) => {
		let location: keyof typeof FETCH_PLATFORMS;
		if (!(l in FETCH_PLATFORMS)) {
			location = Object.entries(FETCH_PLATFORMS)
				.filter(([, value]) => l === value)
				.map<keyof typeof FETCH_PLATFORMS>(([key]) => key as keyof typeof FETCH_PLATFORMS)
				.find(() => true);
			if (!location) {
				throw new Error(`Unknown fetch platform was chosen: ${l}!`);
			}
		} else {
			location = l as keyof typeof FETCH_PLATFORMS;
		}

		let url: string, path: string, pathSections: (string | number)[], key: string;
		const headers: { [key: string]: string } = {};

		const params = new URLSearchParams();
		switch (location) {
			case "tornv2":
				url = FETCH_PLATFORMS.tornv2;

				path = `${options.section}/${options.id || ""}`;

				params.append("selections", [...options.selections, ...options.legacySelections].join(","));
				params.append("legacy", options.legacySelections.join(","));
				params.append("key", options.key || api.torn.key);
				if (settings.apiUsage.comment) {
					params.append("comment", settings.apiUsage.comment);
				}

				await ttUsage.add(location);
				break;
			case "torn_direct":
				url = FETCH_PLATFORMS.torn_direct;

				path = options.action;

				params.set("rfcv", getRFC());
				break;
			case "tornstats":
				url = FETCH_PLATFORMS.tornstats;

				pathSections = ["api", "v2", options.key || api.tornstats.key || api.torn.key];
				if (options.section) pathSections.push(options.section);
				if (options.id) pathSections.push(options.id);

				path = pathSections.join("/");
				await ttUsage.add(location);
				break;
			case "yata":
				url = FETCH_PLATFORMS.yata;

				pathSections = ["api", "v1", options.section];
				if (options.id) pathSections.push(options.id, "");
				if (options.includeKey) key = api.yata.key;

				path = pathSections.join("/");
				await ttUsage.add(location);
				break;
			case "prometheus":
				url = FETCH_PLATFORMS.prometheus;
				path = ["api", options.section].join("/");
				break;
			case "tornw3b":
				url = FETCH_PLATFORMS.tornw3b;
				path = ["api", options.section].join("/");
				break;
			case "ffscouter":
				url = FETCH_PLATFORMS.ffscouter;
				path = ["api", "v1", options.section].join("/");
				key = api.ffScouter.key;
				break;
			case "tornintel":
				url = FETCH_PLATFORMS.tornintel;
				path = ["api", options.section].join("/");
				break;
			default:
				url = FETCH_PLATFORMS[location];
				path = options.section;
				break;
		}

		if (options.includeKey) {
			params.append("key", options.key || key || api.torn.key);
		}

		if (options.params) {
			for (const [key, value] of Object.entries(options.params)) {
				params.append(key, value.toString());
			}
		}

		const fullUrl = `${url}${path}${params.toString() ? `?${params}` : ""}`;
		let parameters = {};

		if (options.method.toUpperCase() === "POST") {
			let body: any;
			if (options.body instanceof URLSearchParams) body = options.body;
			else {
				body = JSON.stringify(options.body);
				headers["content-type"] = "application/json";
			}

			if (location === "torn_direct") {
				headers["x-requested-with"] = "XMLHttpRequest";
			}

			parameters = { method: "POST", body };
		}

		const controller = new AbortController();
		const timeoutId = setTimeout(() => controller.abort(), decideTimeoutTimer(l));

		fetch(fullUrl, { ...parameters, headers, signal: controller.signal })
			.then(async (response) => {
				let result: any = {};

				try {
					result = await response.clone().json();
				} catch (error) {
					if (location === "torn_direct" || location === "laekna") {
						result = await response.clone().text();

						resolve(result);
						return;
					} else {
						if (controller.signal.aborted) {
							result.success = false;
							result.error = error;
						} else if (response.status === 200) {
							result.success = true;
						} else {
							result.success = false;
							result.error = new HTTPException(response.status);
						}

						result.metadata = {
							error,
							response,
							signal: controller.signal,
						};
					}
				}

				if (options.fakeResponse) {
					result = options.fakeResponse;
				}

				if (result.error) {
					await handleError(result);
				} else {
					if (isTornAPICall(location) && !options.silent && SCRIPT_TYPE === "BACKGROUND") {
						await getBadgeText()
							.then(async (value) => {
								if (value === "error") await setBadge("default");
							})
							.catch(() => console.error("TT - Couldn't get the badge text."));

						await ttStorage.change({ api: { torn: { online: true, error: "" } } });
					}

					resolve(result);
				}
			})
			.catch((error) => handleError(error))
			.then(() => clearTimeout(timeoutId));

		return fullUrl;

		async function handleError(result: any) {
			if (options.succeedOnError) {
				resolve(result);
				await ttUsage.add(location);
				return;
			}

			if (result instanceof DOMException) {
				const error = "Request cancelled because it took too long.";
				const isLocal = false;
				const code = CUSTOM_API_ERROR.CANCELLED;

				if (isTornAPICall(location) && !options.silent && SCRIPT_TYPE === "BACKGROUND") {
					await ttStorage.change({ api: { torn: { online: false, error } } });
					await setBadge("error");
				}
				reject({ error, isLocal, code });
			} else if (result.constructor.name === "TypeError") {
				let error = result.message;
				let isLocal = false;
				let code: string | undefined;

				if (error === "Failed to fetch") {
					isLocal = true;
					if (SCRIPT_TYPE === "BACKGROUND" && !(await hasOrigins(url))) {
						error = "Permission issues";
						code = CUSTOM_API_ERROR.NO_PERMISSION;
					} else {
						error = "Network issues";
						code = CUSTOM_API_ERROR.NO_NETWORK;
					}
				}

				if (isTornAPICall(location) && !options.silent && SCRIPT_TYPE === "BACKGROUND") {
					await ttStorage.change({ api: { torn: { online: false, error } } });
					await setBadge("error");
				}
				reject({ error, isLocal, code });
			} else if (isTornAPICall(location)) {
				let error: string, online: boolean;

				if (result.error instanceof HTTPException) {
					error = result.error.toString();
					online = false;
				} else {
					error = result.error.error;
					online = result.error.code !== 9 && !(result instanceof HTTPException);
				}

				if (!options.silent && SCRIPT_TYPE === "BACKGROUND") {
					await ttStorage.change({ api: { torn: { online, error } } });
					await setBadge("error");
				}

				if (result.error instanceof HTTPException) {
					reject(result.error.asObject());
				} else {
					reject(result.error);
				}
			} else {
				reject({ error: result.error });
			}
		}
	});
}

function decideTimeoutTimer(location: FetchLocation): number {
	switch (location) {
		case "yata":
			return 30 * TO_MILLIS.SECONDS;
		default:
			return 10 * TO_MILLIS.SECONDS;
	}
}

export function isTornAPICall(location: FetchLocation) {
	return ["tornv2"].includes(location);
}

export async function checkAPIPermission(key: string) {
	try {
		const response = await fetchData("tornv2", { section: "key", selections: ["info"], key, silent: true });
		const { type, faction, company } = response.info.access;

		if (type === "Limited Access" || type === "Full Access") {
			return { access: true, faction, company };
		} else {
			return { access: false };
		}
	} catch (error) {
		throw error.error;
	}
}

export async function changeAPIKey(key: string): Promise<void> {
	try {
		await fetchData("tornv2", { section: "user", selections: ["basic"], key, silent: true });
		await ttStorage.change({ api: { torn: { key } } });

		await BACKGROUND_SERVICE.initialize();
	} catch (error) {
		throw error.error;
	}
}

export function hasAPIData(): boolean {
	const hasKey = !!api?.torn?.key;
	const hasError = !!api?.torn?.error && !api.torn.error.includes("Backend error") && api.torn.error !== "Network issues";
	const hasUserdata = !!(userdata && Object.keys(userdata).length);

	return hasKey && !hasError && hasUserdata;
}

export function hasFactionAPIAccess(): boolean {
	if (!hasAPIData()) return false;

	return userdata.faction && factiondata?.access === FACTION_ACCESS.full_access;
}

export function hasOC2Data(): boolean {
	if (!hasAPIData() || !("organizedCrime" in userdata)) return false;

	return userdata.organizedCrime === null || !("error" in userdata.organizedCrime);
}

export function hasOC1Data(): boolean {
	if (!hasAPIData() || !("organizedCrime" in userdata)) return false;

	// 27: "Must be migrated to organized crimes 2.0"
	return userdata.organizedCrime !== null && "code" in userdata.organizedCrime && userdata.organizedCrime.code === 27;
}

async function hasOrigins(...origins: string[]): Promise<boolean> {
	// We have permission for the entire domain, not just the api subdomain.
	origins = origins.map((origin) => origin.replaceAll("api.torn.com", "torn.com"));

	return browser.permissions.contains({ origins });
}

export class HTTPException {
	private readonly code: number;

	constructor(code: number) {
		this.code = code;
	}

	get message() {
		return this.code in HTTPException.codes ? HTTPException.codes[this.code] : `Unknown code (${this.code})`;
	}

	asObject() {
		return { code: this.code, message: this.message, http: true };
	}

	toString() {
		return `HTTP ${this.code}: ${this.message}`;
	}

	static get codes(): { [code: number]: string } {
		return {
			200: "OK",
			201: "Created",
			202: "Accepted",
			203: "Non-Authoritative Information",
			204: "No Content",
			205: "Reset Content",
			206: "Partial Content",
			300: "Multiple Choices",
			301: "Moved Permanently",
			302: "Found",
			303: "See Other",
			304: "Not Modified",
			305: "Use Proxy",
			306: "Unused",
			307: "Temporary Redirect",
			400: "Bad Request",
			401: "Unauthorized",
			402: "Payment Required",
			403: "Forbidden",
			404: "Not Found",
			405: "Method Not Allowed",
			406: "Not Acceptable",
			407: "Proxy Authentication Required",
			408: "Request Timeout",
			409: "Conflict",
			410: "Gone",
			411: "Length Required",
			412: "Precondition Required",
			413: "Request Entry Too Large",
			414: "Request-URI Too Long",
			415: "Unsupported Media Type",
			416: "Requested Range Not Satisfiable",
			417: "Expectation Failed",
			418: "I'm a teapot",
			429: "Too Many Requests",
			500: "Internal Server Error",
			501: "Not Implemented",
			502: "Bad Gateway",
			503: "Service Unavailable",
			504: "Gateway Timeout",
			505: "HTTP Version Not Supported",
		};
	}
}

export function isTornApiError(response: any): response is ApiError {
	return !!response && typeof response === "object" && "error" in response && "code" in response;
}
